import scala.collection.mutable.PriorityQueue
import scala.collection.mutable.HashMap

def solve(n: Long, edges: Array[Array[Long]]): Long = {
  // Build adjacency list
  val graph = HashMap[Long, List[(Long, Long, Long)]]()
  for (edge <- edges) {
    val u = edge(0)
    val v = edge(1)
    val start = edge(2)
    val end = edge(3)
    if (!graph.contains(u)) {
      graph(u) = List()
    }
    graph(u) = (v, start, end) :: graph(u)
  }

  // Priority queue: (time, node)
  val pq = PriorityQueue[(Long, Long)]()
  pq.enqueue((0, 0))

  // Visited dictionary to keep track of the earliest time we reach each node
  val visited = HashMap[Long, Long]()

  while (pq.nonEmpty) {
    val (time, node) = pq.dequeue()

    // If we have already reached this node with an earlier time, skip
    if (visited.contains(node) && visited(node) <= time) {
      continue
    }

    // Mark the earliest time we reach this node
    visited(node) = time

    // If we reached the destination node, return the time
    if (node == n - 1) {
      return time
    }

    // Explore neighbors
    for (neighbor <- graph.getOrElse(node, List())) {
      val (v, start, end) = neighbor
      // We can only take the edge if the current time is within the allowed range
      if (start <= time && time <= end) {
        // We can take the edge and move to the neighbor at time + 1
        val newTime = time + 1
        if (!visited.contains(v) || newTime < visited(v)) {
          pq.enqueue((newTime, v))
        }
      } else {
        // If the edge is not available at current time, we can wait until the start time
        // and then take the edge
        val waitTime = start - time
        if (waitTime > 0) {
          val newTime = start + 1
          if (!visited.contains(v) || newTime < visited(v)) {
            pq.enqueue((newTime, v))
          }
        } else {
          // If the edge is not available at current time, we can't take it now
          // So we wait until the start time and then take it
          val newTime = start + 1
          if (!visited.contains(v) || newTime < visited(v)) {
            pq.enqueue((newTime, v))
          }
        }
      }
    }
  }

  // If we exhaust all possibilities and haven't reached the destination
  -1
}
